fun solve(code: Array<String>, businessLine: Array<String>, isActive: Array<Boolean>): Array<String> {
    val validBusinessLines = setOf("electronics", "grocery", "pharmacy", "restaurant")
    val businessOrder = mapOf(
        "electronics" to 0,
        "grocery" to 1,
        "pharmacy" to 2,
        "restaurant" to 3
    )

    val validCoupons = mutableListOf<Pair<String, String>>()

    for (i in code.indices) {
        if (!isActive[i]) continue

        val bl = businessLine[i]
        if (bl !in validBusinessLines) continue

        val cd = code[i]
        if (cd.isEmpty()) continue
        if (!cd.all { it.isLetterOrDigit() || it == '_' }) continue

        validCoupons.add(cd to bl)
    }

    validCoupons.sortWith(compareBy(
        { (_, business) -> businessOrder[business] },
        { (cd, _) -> cd }
    ))

    return validCoupons.map { it.first }.toTypedArray()
}
